lgg_patient_barcodes = set()
for patient in lgg_patients:
    desc = patient['Patient_description']
    start = desc.find('TCGA-')
    if start != -1:
        end = desc.find(' ', start)
        if end == -1:
            end = len(desc)
        lgg_patient_barcodes.add(desc[start:end].strip())

print('__RESULT__:')
print(json.dumps(list(lgg_patient_barcodes)))

